def prime_trial_division(n):
    """
    Üç deneme bölme kullanarak n'ye kadar asal sayıları üretir.
    """
    primes = []
    for num in range(2, n + 1):
        is_prime = True
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                is_prime = False
                break
        if is_prime:
            primes.append(num)
    return primes

if __name__ == '__main__':
    limit = 50  # Örnek sınır
    prime_numbers = prime_trial_division(limit)
    print(f"{limit}ye kadar asal sayılar: {prime_numbers}")
